// App.js
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import Sidebar from './components/layout/Sidebar';
import DashboardContent from './components/layout/DashboardContent';
import AccessManagementContent from './components/layout/AccessManagementContent';
import AddAccessContent from './components/layout/AddAccessContent';
import PlateformeManagementContent from './components/layout/PlateformeManagementContent';
import LoginForm from './components/layout/LoginForm';
import AddUserForm from './components/layout/AddUserForm';
import UserManagementContent from './components/layout/UserManagementContent';
import RequireAuth from './components/auth/RequireAuth';
import ProtectedRoute from './components/auth/ProtectedRoute';
import Unauthorized from './components/layout/unauthorized';
//import { useEffect } from 'react';

function LayoutRoutes() {
  const location = useLocation();
  const hideSidebarRoutes = ['/login']; // 🚫 Liste des routes sans sidebar
  const hideSidebar = hideSidebarRoutes.includes(location.pathname);

  return (
    <div className="flex min-h-screen bg-gray-50">
      {!hideSidebar && <Sidebar />}
      <div className="flex-1">
        <Routes>
          <Route path="/unauthorized" element={<Unauthorized />} />
          <Route path="/login" element={<LoginForm />} />
          <Route path="/" element={<Navigate to="/dashboard" replace />} />
          <Route path="/dashboard" element={<RequireAuth><DashboardContent /></RequireAuth>} />
          <Route path="/access" element={<RequireAuth><AccessManagementContent /></RequireAuth>} />
          <Route path="/access/add" element={<ProtectedRoute allowedRoles={['ADMIN']}>
            <RequireAuth><AddAccessContent /></RequireAuth>
          </ProtectedRoute>} />
          <Route path="/access/:accessId" element={
            <RequireAuth><AddAccessContent /></RequireAuth>
          } />
          <Route path="/setting" element={<ProtectedRoute allowedRoles={['ADMIN']}>
            <RequireAuth><PlateformeManagementContent /></RequireAuth>
          </ProtectedRoute>} />
          <Route path="/users" element={<ProtectedRoute allowedRoles={['ADMIN']}>
            <RequireAuth><UserManagementContent /></RequireAuth>
          </ProtectedRoute>} />
          <Route path="/users/add" element={<ProtectedRoute allowedRoles={['ADMIN']}>
            <RequireAuth><AddUserForm mode="add" /></RequireAuth>
          </ProtectedRoute>} />
          <Route path="/users/:usersId" element={<ProtectedRoute allowedRoles={['ADMIN']}>
            <RequireAuth><AddUserForm /></RequireAuth> 
          </ProtectedRoute>} />

        </Routes>
      </div>
    </div>
  );
}

export default function App() {
  return (
    <Router>
      <LayoutRoutes />
    </Router>
  );
}
